import yaml
from pathlib import Path
from typing import Any

def load_spec(path: str) -> dict[str, Any]:
    """Load and return an OpenAPI 3.x spec from a YAML or JSON file."""
    text = Path(path).read_text()
    return yaml.safe_load(text)

def extract_operations(spec: dict) -> list[dict]:
    """
    Yield each operation as a flat dict with:
      method, path, operation_id, summary, parameters, request_body, responses
    """
    operations = []
    for path_str, path_item in spec.get("paths", {}).items():
        for method in ("get", "post", "put", "patch", "delete"):
            op = path_item.get(method)
            if op is None:
                continue
            operations.append({
                "method": method.upper(),
                "path": path_str,
                "operation_id": op.get("operationId", f"{method}_{path_str.replace('/', '_')}"),
                "summary": op.get("summary", ""),
                "description": op.get("description", ""),
                "parameters": op.get("parameters", []),
                "request_body": op.get("requestBody"),
                "responses": op.get("responses", {}),
                "tags": op.get("tags", []),
            })
    return operations

# Example
spec = {
    "openapi": "3.0.0",
    "paths": {
        "/orders/{order_id}": {
            "get": {
                "operationId": "getOrder",
                "summary": "Fetch an order by ID",
                "parameters": [
                    {"name": "order_id", "in": "path", "required": True,
                     "schema": {"type": "string"}}
                ],
                "responses": {"200": {"description": "Order object"}},
            }
        }
    }
}
ops = extract_operations(spec)
print(ops[0]["operation_id"])  # getOrder

import re

def _to_snake(s: str) -> str:
    s = re.sub(r"([A-Z]+)([A-Z][a-z])", r"\1_\2", s)
    s = re.sub(r"([a-z0-9])([A-Z])", r"\1_\2", s)
    return s.lower()

def _param_to_property(param: dict) -> tuple[str, dict]:
    """Convert an OpenAPI parameter object to a JSON Schema property."""
    schema = param.get("schema", {})
    prop: dict = {"type": schema.get("type", "string")}
    if "description" in param:
        prop["description"] = param["description"]
    if "enum" in schema:
        prop["enum"] = schema["enum"]
    if schema.get("type") == "array":
        prop["items"] = schema.get("items", {"type": "string"})
    return param["name"], prop

def operation_to_tool(op: dict) -> dict:
    """Convert a parsed OpenAPI operation to a Claude tool definition."""
    name = _to_snake(op["operation_id"])
    description = op["summary"] or op["description"] or name
    # Truncate very long descriptions
    if len(description) > 250:
        description = description[:247] + "..."

    properties: dict[str, dict] = {}
    required: list[str] = []

    for param in op["parameters"]:
        pname, prop = _param_to_property(param)
        properties[pname] = prop
        if param.get("required"):
            required.append(pname)

    # Handle request body (simplified: extract first content type's schema)
    rb = op.get("request_body")
    if rb:
        content = rb.get("content", {})
        for media_type in ("application/json", "application/x-www-form-urlencoded"):
            if media_type in content:
                body_schema = content[media_type].get("schema", {})
                for field, field_schema in body_schema.get("properties", {}).items():
                    properties[field] = field_schema
                if rb.get("required"):
                    required += body_schema.get("required", [])
                break

    tool = {
        "name": name,
        "description": description,
        "input_schema": {
            "type": "object",
            "properties": properties,
        },
    }
    if required:
        tool["input_schema"]["required"] = required
    return tool

