tool = operation_to_tool(ops[0])
print(tool["name"])          # get_order
print(tool["description"])   # Fetch an order by ID

import requests
from urllib.parse import urlencode

class OpenAPIDispatcher:
    def __init__(self, spec: dict, base_url: str, headers: dict | None = None):
        self.base_url = base_url.rstrip("/")
        self.headers  = headers or {}
        # Index operations by snake_case tool name
        self._ops: dict[str, dict] = {}
        for op in extract_operations(spec):
            name = _to_snake(op["operation_id"])
            self._ops[name] = op

    def dispatch(self, tool_name: str, inputs: dict) -> dict:
        op = self._ops.get(tool_name)
        if op is None:
            return {"error": "NOT_FOUND", "message": f"No operation for tool: {tool_name}"}

        # Separate inputs into path params, query params, body
        path_params = {}
        query_params = {}
        body = {}
        param_names = {p["name"] for p in op["parameters"]}

        for p in op["parameters"]:
            val = inputs.get(p["name"])
            if val is None:
                continue
            if p["in"] == "path":
                path_params[p["name"]] = val
            elif p["in"] == "query":
                query_params[p["name"]] = val

        if op.get("request_body"):
            body = {k: v for k, v in inputs.items() if k not in param_names}

        # Build URL
        path = op["path"]
        for key, val in path_params.items():
            path = path.replace(f"{{{key}}}", str(val))
        url = self.base_url + path
        if query_params:
            url = url + "?" + urlencode(query_params)

        try:
            resp = requests.request(
                method=op["method"],
                url=url,
                json=body if body else None,
                headers=self.headers,
                timeout=(5, 15),
            )
        except requests.Timeout:
            return {"error": "TIMEOUT", "message": f"{tool_name} timed out", "retry_after_seconds": 15}
        except Exception as exc:
            return {"error": "SERVICE_UNAVAILABLE", "message": str(exc)}

        if resp.status_code == 404:
            return {"error": "NOT_FOUND", "message": f"Resource not found: {url}"}
        if resp.status_code >= 400:
            return {"error": "HTTP_ERROR", "status": resp.status_code, "message": resp.text[:300]}

        try:
            return resp.json()
        except ValueError:
            return {"content": resp.text[:2000]}

import anthropic

PETSTORE_SPEC = {
    "openapi": "3.0.0",
    "paths": {
        "/pets": {
            "get": {
                "operationId": "listPets",
                "summary": "List all pets, optionally filtered by type",
                "parameters": [
                    {"name": "type", "in": "query", "required": False,
                     "schema": {"type": "string", "enum": ["dog", "cat", "bird"]}},
                    {"name": "limit", "in": "query", "required": False,
                     "schema": {"type": "integer"}},
                ],
                "responses": {"200": {"description": "List of pets"}},
            }
        },
        "/pets/{pet_id}": {
            "get": {
                "operationId": "getPet",
                "summary": "Fetch a single pet by ID",
                "parameters": [
                    {"name": "pet_id", "in": "path", "required": True,
                     "schema": {"type": "string"}},
                ],
                "responses": {"200": {"description": "Pet object"}},
            }
        },
    }
}

dispatcher = OpenAPIDispatcher(
    spec=PETSTORE_SPEC,
    base_url="https://petstore.example.com",
    headers={"Authorization": "Bearer sk-test"},
)

ops = extract_operations(PETSTORE_SPEC)
tools = [operation_to_tool(op) for op in ops]

client = anthropic.Anthropic()

def run_agent(user_message: str) -> str:
    messages = [{"role": "user", "content": user_message}]
    while True:
        resp = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=1024,
            tools=tools,
            messages=messages,
        )
        if resp.stop_reason == "end_turn":
            return next(b.text for b in resp.content if hasattr(b, "text"))
        messages.append({"role": "assistant", "content": resp.content})
        results = []
        for block in resp.content:
            if block.type == "tool_use":
                result = dispatcher.dispatch(block.name, block.input)
                results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": str(result),
                })
        messages.append({"role": "user", "content": results})
